import TemplateBrowser from "@/components/templates/TemplateBrowser";

/**
 * Home page — a welcoming template gallery.
 *
 * Server Component that renders the app title, subtitle, and the client-side
 * TemplateBrowser for horizontal-scrolling template cards. No 3D canvas on
 * this page — keeps it lightweight and fast to load.
 */
export default function Home() {
  return (
    <main className="min-h-screen bg-gradient-to-b from-white to-gray-50 flex flex-col home-page-root">
      {/* Hero section */}
      <header className="px-4 pt-12 pb-8 flex flex-col gap-2">
        <h1 className="text-3xl font-extrabold text-gray-900 tracking-tight">
          Конструктор бусин
        </h1>
        <p className="text-base text-gray-500 leading-relaxed">
          Выберите шаблон или создайте своё изделие
        </p>
      </header>

      {/* Template gallery */}
      <TemplateBrowser />

      {/* Footer spacer */}
      <div className="flex-1" />
      <footer className="px-4 py-6 text-center">
        <span className="text-xs text-gray-300">
          Toy Designer &middot; бисероплетение
        </span>
      </footer>
    </main>
  );
}

"use client";

import Link from "next/link";
import { decodeDesign } from "@/lib/serialization";
import { getCatalogBead } from "@/data/catalogBeads";

interface TemplateCardProps {
  name: string;
  designCode: string;
  beadCount: number;
}

const MAX_PREVIEW_DOTS = 8;
const FALLBACK_COLOR = "#D1D5DB"; // gray-300

/**
 * Individual template card with bead-color preview dots.
 *
 * Decodes the design code to extract catalog bead IDs, then renders
 * small colored circles for the first N beads. Falls back to gray
 * for any bead whose catalog ID can't be resolved.
 */
export default function TemplateCard({
  name,
  designCode,
  beadCount,
}: TemplateCardProps) {
  const design = decodeDesign(designCode);
  const beadIds = design?.b ?? [];

  const previewColors = beadIds.slice(0, MAX_PREVIEW_DOTS).map((id) => {
    const bead = getCatalogBead(id);
    return bead?.color ?? FALLBACK_COLOR;
  });

  const beadWord =
    beadCount % 10 === 1 && beadCount % 100 !== 11
      ? "бусина"
      : beadCount % 10 >= 2 && beadCount % 10 <= 4 && (beadCount % 100 < 12 || beadCount % 100 > 14)
        ? "бусины"
        : "бусин";

  return (
    <Link
      href={`/design/${designCode}`}
      className="group flex-shrink-0 w-40 snap-start"
    >
      <div className="bg-white rounded-xl shadow-sm hover:shadow-md transition-all border border-gray-100 p-4 active:scale-95 min-h-[120px] flex flex-col gap-3">
        {/* Bead color preview dots */}
        <div className="flex items-center gap-1.5 flex-wrap min-h-[24px]">
          {previewColors.map((color, i) => (
            <span
              key={i}
              className="block w-2 h-2 rounded-full shrink-0"
              style={{ backgroundColor: color }}
              aria-hidden="true"
            />
          ))}
        </div>

        {/* Template info */}
        <div className="flex flex-col gap-0.5">
          <span className="font-semibold text-sm text-gray-800 leading-tight line-clamp-2 group-hover:text-gray-600 transition-colors">
            {name}
          </span>
          <span className="text-xs text-gray-400">
            {beadCount} {beadWord}
          </span>
        </div>
      </div>
    </Link>
  );
}

"use client";

import { useEffect, useState, useCallback } from "react";
import Link from "next/link";
import TemplateCard from "./TemplateCard";

interface Template {
  id: string;
  name: string;
  designCode: string;
  beadCount: number;
  isApproved: boolean;
  isUserSubmitted: boolean;
  createdAt: string;
}

/**
 * Horizontal-scrolling template gallery.
 *
 * Fetches approved templates from the API on mount and renders them as
 * horizontally scrollable cards. Includes a "Начать с нуля" card that
 * links to the blank editor, plus loading and error states.
 */
export default function TemplateBrowser() {
  const [templates, setTemplates] = useState<Template[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const fetchTemplates = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const res = await fetch("/api/templates");
      if (!res.ok) {
        throw new Error(`HTTP ${res.status}`);
      }
      const data: Template[] = await res.json();
      setTemplates(data);
    } catch (err) {
      console.error("Failed to fetch templates:", err);
      setError("Не удалось загрузить шаблоны");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchTemplates();
  }, [fetchTemplates]);

  return (
    <section>
      <h2 className="text-lg font-bold text-gray-800 px-4 mb-3">Шаблоны</h2>

      {/* Loading state — skeleton cards */}
      {loading && (
        <div className="flex gap-4 overflow-x-auto px-4 pb-4" aria-label="Загрузка шаблонов">
          {Array.from({ length: 4 }).map((_, i) => (
            <div
              key={i}
              className="flex-shrink-0 w-40 animate-pulse"
            >
              <div className="bg-gray-100 rounded-xl h-[120px] flex flex-col gap-3 p-4">
                <div className="flex gap-1.5 flex-wrap">
                  {Array.from({ length: 6 }).map((_, j) => (
                    <span
                      key={j}
                      className="block w-2 h-2 rounded-full bg-gray-200"
                    />
                  ))}
                </div>
                <div className="flex flex-col gap-1.5">
                  <div className="h-4 bg-gray-200 rounded w-24" />
                  <div className="h-3 bg-gray-200 rounded w-16" />
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Error state */}
      {!loading && error && (
        <div className="px-4 py-6 text-center">
          <p className="text-sm text-red-500 mb-3">{error}</p>
          <button
            type="button"
            onClick={fetchTemplates}
            className="text-sm font-medium text-blue-600 hover:text-blue-800 transition-colors"
          >
            Попробовать снова
          </button>
        </div>
      )}

      {/* Template cards + "Начать с нуля" */}
      {!loading && !error && (
        <div className="flex gap-4 overflow-x-auto px-4 pb-4 snap-x scrollbar-hide">
          {/* "Начать с нуля" card */}
          <Link
            href="/editor"
            className="flex-shrink-0 w-40 snap-start"
          >
            <div className="bg-white rounded-xl shadow-sm border-2 border-dashed border-gray-300 hover:border-gray-400 transition-all p-4 active:scale-95 min-h-[120px] flex flex-col items-center justify-center gap-2">
              <span className="text-2xl text-gray-400 leading-none select-none">+</span>
              <span className="text-xs font-medium text-gray-500 text-center leading-tight">
                Начать<br />с нуля
              </span>
            </div>
          </Link>

          {templates.map((t) => (
            <TemplateCard
              key={t.id}
              name={t.name}
              designCode={t.designCode}
              beadCount={t.beadCount}
            />
          ))}
        </div>
      )}
    </section>
  );
}

import LZString from "lz-string";
import type { BeadState, SerializableDesign } from "@/types/bead";

/**
 * Encode an array of BeadState objects into a URL-safe design code.
 *
 * Pipeline: filter beads with catalogBeadId → JSON.stringify → LZ-String compress → base64url.
 * Only beads that have a `catalogBeadId` are included; others are silently skipped.
 */
export function encodeDesign(beads: BeadState[]): string {
  const catalogIds = beads
    .filter((b) => b.catalogBeadId)
    .map((b) => b.catalogBeadId as string);

  const design: SerializableDesign = {
    v: 1,
    p: "pacifier-holder",
    b: catalogIds,
  };

  return LZString.compressToEncodedURIComponent(JSON.stringify(design));
}

/**
 * Decode a URL-safe design code back into a SerializableDesign.
 *
 * Applies `decodeURIComponent` first because lz-string output may contain
 * `+` which browsers encode as `%2B` in URL path segments, and Next.js
 * does not decode `%2B` back to `+` in dynamic route params.
 *
 * Returns `null` for any invalid input: malformed base64url, invalid JSON,
 * missing required fields, or unsupported version.
 */
export function decodeDesign(code: string): SerializableDesign | null {
  if (!code || typeof code !== "string") return null;

  try {
    // Normalize URL-encoded characters (e.g. %2B → +) that may appear
    // when design codes are embedded in URL path segments.
    const normalized = decodeURIComponent(code);

    const json = LZString.decompressFromEncodedURIComponent(normalized);
    if (!json) return null;

    const parsed: unknown = JSON.parse(json);

    const obj = parsed as Record<string, unknown>;
    if (obj.v !== 1 || typeof obj.p !== "string" || !Array.isArray(obj.b)) {
      return null;
    }
    if (!(obj.b as unknown[]).every((id) => typeof id === "string")) {
      return null;
    }

    return parsed as SerializableDesign;
  } catch {
    return null;
  }
}

